import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import './Projects.css';

const Projects = () => {
  const [currentProject, setCurrentProject] = useState(0);

  const projects = [
    {
      title: "GearNexus E-commerce Platform",
      description: "Full-stack e-commerce platform with React frontend and Node.js backend, featuring user authentication and payment integration.",
      tags: ["React", "Node.js", "MongoDB", "Stripe"],
      image: "/images/Gearnexusweb.png",
      liveUrl: "https://example.com/gearnexus",
      githubUrl: "https://github.com/username/gearnexus"
    },
    {
      title: "EZ Health Mobile App",
      description: "Healthcare mobile application for appointment booking and patient management with real-time notifications.",
      tags: ["React Native", "Firebase", "Node.js", "Express"],
      image: "/images/ez_health_mobile.png",
      liveUrl: "https://example.com/ezhealth",
      githubUrl: "https://github.com/username/ezhealth"
    },
    {
      title: "AI Text Summarizer",
      description: "AI-powered text summarization tool using natural language processing to generate concise summaries from long documents.",
      tags: ["Python", "NLP", "React", "OpenAI"],
      image: "/images/ai_text_summarizer.png",
      liveUrl: "https://example.com/summarizer",
      githubUrl: "https://github.com/username/ai-summarizer"
    },
    {
      title: "TTalks Communication Platform",
      description: "Real-time communication platform with video calls, messaging, and file sharing capabilities.",
      tags: ["React", "WebRTC", "Socket.io", "Node.js"],
      image: "/images/TTalks.png",
      liveUrl: "https://example.com/ttalks",
      githubUrl: "https://github.com/username/ttalks"
    },
    {
      title: "PaperSum Document Manager",
      description: "Document management system with automated summarization and categorization features for research papers.",
      tags: ["React", "Python", "ML", "PostgreSQL"],
      image: "/images/papersum1.png",
      liveUrl: "https://example.com/papersum",
      githubUrl: "https://github.com/username/papersum"
    }
  ];

  const nextProject = () => {
    setCurrentProject((prev) => (prev + 1) % projects.length);
  };

  const prevProject = () => {
    setCurrentProject((prev) => (prev - 1 + projects.length) % projects.length);
  };

  const goToProject = (index) => {
    setCurrentProject(index);
  };

  return (
    <section id="projects" className="projects-section">
      <div className="container">
        <motion.h2 
          className="section-title"
          initial={{ opacity: 0, y: -20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          Featured Projects
        </motion.h2>

        <div className="carousel-container">
          <button className="carousel-btn prev" onClick={prevProject}>
            &#8249;
          </button>

          <div className="carousel-wrapper">
            <AnimatePresence mode="wait">
              <motion.div
                key={currentProject}
                className="project-card"
                initial={{ opacity: 0, x: 300 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -300 }}
                transition={{ duration: 0.5 }}
              >
                <div className="project-image">
                  <img 
                    src={projects[currentProject].image} 
                    alt={projects[currentProject].title}
                    onError={(e) => {
                      e.target.src = `https://via.placeholder.com/600x300/1a1a2e/4a9eff?text=${encodeURIComponent(projects[currentProject].title)}`;
                    }}
                  />
                </div>
                <div className="project-content">
                  <h3>{projects[currentProject].title}</h3>
                  <p>{projects[currentProject].description}</p>
                  <div className="tech-tags">
                    {projects[currentProject].tags.map((tag, i) => (
                      <span key={i} className="tech-tag">{tag}</span>
                    ))}
                  </div>
                  <div className="project-links">
                    <a href={projects[currentProject].liveUrl} target="_blank" rel="noopener noreferrer" className="project-link live">
                      View Live
                    </a>
                    <a href={projects[currentProject].githubUrl} target="_blank" rel="noopener noreferrer" className="project-link github">
                      GitHub
                    </a>
                  </div>
                </div>
              </motion.div>
            </AnimatePresence>
          </div>

          <button className="carousel-btn next" onClick={nextProject}>
            &#8250;
          </button>
        </div>

        <div className="carousel-indicators">
          {projects.map((_, index) => (
            <button
              key={index}
              className={`indicator ${index === currentProject ? 'active' : ''}`}
              onClick={() => goToProject(index)}
            />
          ))}
        </div>
      </div>
    </section>
  );
};

export default Projects;
